 : 'Escribe para buscar...' }}</span>\r\n                                    </template>\r\n                                </v-select>\r\n                            </div>\r\n                            <div class=\"col-12 col-md-2\">\r\n                                <label class=\"font-weight-bold mb-1\" style=\"font-size:11px;\">MARCA</label>\r\n                                <v-select\r\n                                    v-model=\"filtros.marca_id\"\r\n                                    :options=\"lst_marcas\"\r\n                                    :reduce=\"m => m.id\"\r\n                                    label=\"descripcion\"\r\n                                    :filterable=\"false\"\r\n                                    placeholder=\"Todas\"\r\n                                    @search=\"onSearchMarca\">\r\n                                    <template #no-options=\"{ search }\">\r\n                                        <span style=\"font-size:12px;\">{{ search ? 'Sin resultados' : 'Escribe para buscar...' }}</span>\r\n                                    </template>\r\n                                </v-select>\r\n                            </div>\r\n                            <div class=\"col-12 col-md-2\">\r\n                                <label class=\"font-weight-bold mb-1\" style=\"font-size:11px;\">CATEGORÍA</label>\r\n                                <v-select\r\n                                    v-model=\"filtros.categoria_id\"\r\n                                    :options=\"lst_categorias\"\r\n                                    :reduce=\"c => c.id\"\r\n                                    label=\"descripcion\"\r\n                                    :filterable=\"false\"\r\n                                    placeholder=\"Todas\"\r\n                                    @search=\"onSearchCategoria\">\r\n                                    <template #no-options=\"{ search }\">\r\n                                        <span style=\"font-size:12px;\">{{ search ? 'Sin resultados' : 'Escribe para buscar...' }}</span>\r\n                                    </template>\r\n                                </v-select>\r\n                            </div>\r\n                            <div class=\"col-12 col-md-2\">\r\n                                <label class=\"font-weight-bold mb-1\" style=\"font-size:11px;\">ALMACÉN</label>\r\n                                <v-select\r\n                                    v-model=\"filtros.almacen_id\"\r\n                                    :options=\"lst_almacenes\"\r\n                                    :reduce=\"a => a.id\"\r\n                                    label=\"descripcion\"\r\n                                    placeholder=\"Todos\">\r\n                                </v-select>\r\n                            </div>\r\n                            <div class=\"col-12 col-md-2 d-flex align-items-end\" style=\"gap:4px;\">\r\n                                <button type=\"button\" class=\"btn btn-primary btn-sm flex-fill\"\r\n                                    @click=\"recargarTabla\">\r\n                                    <i class=\"fas fa-search\"></i> Filtrar\r\n                                </button>\r\n                                <button type=\"button\" class=\"btn btn-secondary btn-sm flex-fill\"\r\n                                    @click=\"limpiarFiltros\">\r\n                                    <i class=\"fas fa-times\"></i> Limpiar\r\n                                </button>\r\n                            </div>\r\n                        </div>\r\n\r\n                        <!-- Leyenda -->\r\n                        <div class=\"mb-2 d-flex align-items-center\" style=\"gap:16px; font-size:12px;\">\r\n                            <span>\r\n                                <span style=\"display:inline-block; width:14px; height:14px; background:#fde8e8; border:1px solid #e9a0a0; vertical-align:middle; margin-right:4px;\"></span>\r\n                                Sin stock lógico\r\n                            </span>\r\n                        </div>\r\n\r\n                        <!-- Tabla DataTable -->\r\n                        <div class=\"table-responsive\">\r\n                            <table id=\"tbl_stock_disponible\"\r\n                                class=\"table table-bordered table-hover table-sm nowrap\"\r\n                                style=\"width:100%; text-transform:uppercase;\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>PRODUCTO</th>\r\n                                        <th>COLOR</th>\r\n                                        <th>TALLA</th>\r\n                                        <th>ALMACÉN</th>\r\n                                        <th>MARCA</th>\r\n                                        <th>CATEGORÍA</th>\r\n                                        <th>STOCK</th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody></tbody>\r\n                            </table>\r\n                        </div>\r\n\r\n                    </div>\r\n\r\n                    <div class=\"modal-footer\">\r\n                        <button type=\"button\" class=\"btn btn-danger btn-sm\" data-dismiss=\"modal\">\r\n                            <i class=\"fa fa-times\"></i> Cerrar\r\n                        </button>\r\n                    </div>\r\n\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport 'datatables.net-responsive-bs4';\r\nimport 'datatables.net-responsive-bs4/css/responsive.bootstrap4.min.css';\r\n\r\nexport default {\r\n    name: 'ModalConsultarStock',\r\n    data() {\r\n        return {\r\n            tabla: null,\r\n            filtros: {\r\n                talla_id:    null,\r\n                color_id:    null,\r\n                marca_id:    null,\r\n                categoria_id: null,\r\n                almacen_id:  null,\r\n            },\r\n            lst_tallas:     [],\r\n            lst_colores:    [],\r\n            lst_marcas:     [],\r\n            lst_categorias: [],\r\n            lst_almacenes:  [],\r\n            searchTimers:   {},\r\n        };\r\n    },\r\n    mounted() {\r\n        const vm = this;\r\n        this.$nextTick(() => {\r\n            vm.initDataTable();\r\n            vm.cargarAlmacenes();\r\n            $('#modal_consultar_stock').on('shown.bs.modal', function () {\r\n                if (vm.tabla) {\r\n                    vm.tabla.columns.adjust();\r\n                }\r\n            });\r\n        });\r\n    },\r\n    methods: {\r\n        initDataTable() {\r\n            const vm = this;\r\n            this.tabla = $('#tbl_stock_disponible').DataTable({\r\n                processing: true,\r\n                serverSide: true,\r\n                responsive: true,\r\n                pageLength: 50,\r\n                ajax: {\r\n                    url: route('ventas.documento.getStockDisponible'),\r\n                    type: 'GET',\r\n                    data(d) {\r\n                        d.talla_id    = vm.filtros.talla_id    || '';\r\n                        d.color_id    = vm.filtros.color_id    || '';\r\n                        d.marca_id    = vm.filtros.marca_id    || '';\r\n                        d.categoria_id = vm.filtros.categoria_id || '';\r\n                        d.almacen_id  = vm.filtros.almacen_id  || '';\r\n                    },\r\n                },\r\n                columns: [\r\n                    { data: 'producto_nombre',   name: 'producto_nombre',  searchable: true  },\r\n                    { data: 'color_nombre',      name: 'co.descripcion',   searchable: true },\r\n                    { data: 'talla_nombre',      name: 't.descripcion',    searchable: true },\r\n                    { data: 'almacen_nombre',    name: 'al.descripcion',   searchable: true },\r\n                    { data: 'marca_nombre',      name: 'ma.marca',   searchable: true },\r\n                    { data: 'categoria_nombre',  name: 'ca.descripcion',   searchable: true },\r\n                    {\r\n                        data: 'stock',\r\n                        name: 'pct.stock',\r\n                        searchable: false,\r\n                        className: 'text-center font-weight-bold',\r\n                        render(data) {\r\n                            const color = data > 0 ? '#1e8449' : '#c0392b';\r\n                            return `<span style=\"color:${color}\">${data}</span>`;\r\n                        },\r\n                    },\r\n                    { data: 'stock_logico', name: 'pct.stock_logico', visible: false, searchable: false },\r\n                ],\r\n                createdRow(row, data) {\r\n                    if (parseInt(data.stock_logico) === 0) {\r\n                        $(row).css('background-color', '#fde8e8');\r\n                    }\r\n                },\r\n                language: {\r\n                    processing:   'Procesando...',\r\n                    search:       'Buscar(producto,color,talla,marca,categoria):',\r\n                    lengthMenu:   'Mostrar _MENU_ registros',\r\n                    info:         'Mostrando _START_ a _END_ de _TOTAL_ registros',\r\n                    infoEmpty:    'Mostrando 0 a 0 de 0 registros',\r\n                    infoFiltered: '(filtrado de _MAX_ total)',\r\n                    zeroRecords:  'No se encontraron resultados.',\r\n                    emptyTable:   'Sin datos disponibles.',\r\n                    paginate: {\r\n                        first:    'Primero',\r\n                        previous: 'Anterior',\r\n                        next:     'Siguiente',\r\n                        last:     'Último',\r\n                    },\r\n                },\r\n                order: [[1, 'asc']],\r\n            });\r\n        },\r\n\r\n        recargarTabla() {\r\n            if (this.tabla) {\r\n                this.tabla.ajax.reload(null, false);\r\n            }\r\n        },\r\n\r\n        limpiarFiltros() {\r\n            this.filtros = {\r\n                talla_id:    null,\r\n                color_id:    null,\r\n                marca_id:    null,\r\n                categoria_id: null,\r\n                almacen_id:  null,\r\n            };\r\n            this.lst_tallas     = [];\r\n            this.lst_colores    = [];\r\n            this.lst_marcas     = [];\r\n            this.lst_categorias = [];\r\n            this.recargarTabla();\r\n        },\r\n\r\n        async cargarAlmacenes() {\r\n            try {\r\n                const res = await this.axios.get(route('utilidades.getAlmacenes'));\r\n                this.lst_almacenes = res.data;\r\n            } catch (e) {\r\n                // silent\r\n            }\r\n        },\r\n\r\n        fetchServerOptions(routeName, search, loading, listKey) {\r\n            clearTimeout(this.searchTimers[listKey]);\r\n            if (!search || search.length < 1) {\r\n                loading(false);\r\n                return;\r\n            }\r\n            const vm = this;\r\n            this.searchTimers[listKey] = setTimeout(async () => {\r\n                loading(true);\r\n                try {\r\n                    const res = await vm.axios.get(route(routeName), { params: { q: search } });\r\n                    vm[listKey] = res.data;\r\n                } catch (e) {\r\n                    // silent\r\n                } finally {\r\n                    loading(false);\r\n                }\r\n            }, 400);\r\n        },\r\n\r\n        onSearchTalla(search, loading) {\r\n            this.fetchServerOptions('utilidades.getTallas', search, loading, 'lst_tallas');\r\n        },\r\n        onSearchColor(search, loading) {\r\n            this.fetchServerOptions('utilidades.getColores', search, loading, 'lst_colores');\r\n        },\r\n        onSearchMarca(search, loading) {\r\n            this.fetchServerOptions('utilidades.getMarcas', search, loading, 'lst_marcas');\r\n        },\r\n        onSearchCategoria(search, loading) {\r\n            this.fetchServerOptions('utilidades.getCategorias', search, loading, 'lst_categorias');\r\n        },\r\n    },\r\n};\r\n</script>\r\n"],"sourceRoot":""}]);
